// Process WordPress posts with embedded featured media
// Mode: Run Once for All Items — aggregates all posts into single output
// Returns structured articles with imageUrl for newsletter thumbnails

const inputItems = $input.all();
let posts = [];

for (const item of inputItems) {
  const data = item.json;
  if (Array.isArray(data)) {
    posts.push(...data);
  } else if (data && typeof data === 'object') {
    posts.push(data);
  }
}

let articles = [];

const toISO = (ts) => {
  if (!ts) return new Date().toISOString();
  try {
    if (typeof ts === 'number') return new Date(ts < 1e12 ? ts * 1000 : ts).toISOString();
    return new Date(ts).toISOString();
  } catch { return new Date().toISOString(); }
};

const stripTags = (html) => {
  if (!html) return '';
  return String(html)
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, '')
    .replace(/\s+/g, ' ')
    .trim();
};

const decodeHTMLEntities = (text) => {
  if (!text) return '';
  const map = { '&amp;':'&','&lt;':'<','&gt;':'>','&quot;':'"','&#39;':"'",'&nbsp;':' ' };
  return text
    .replace(/(&amp;|&lt;|&gt;|&quot;|&#39;|&nbsp;)/g, m => map[m])
    .replace(/(\d+);/g, (_, n) => String.fromCharCode(parseInt(n,10)))
    .replace(/([0-9a-fA-F]+);/g, (_, n) => String.fromCharCode(parseInt(n,16)));
};

const clean = (s) => decodeHTMLEntities(stripTags(s || ''));

const getImageUrl = (post) => {
  try {
    const embedded = post._embedded?.['wp:featuredmedia'];
    if (embedded && embedded[0]) {
      const sizes = embedded[0].media_details?.sizes;
      if (sizes) {
        return sizes.medium_large?.source_url || sizes.medium?.source_url || sizes.thumbnail?.source_url || embedded[0].source_url || '';
      }
      return embedded[0].source_url || '';
    }
    if (post.jetpack_featured_media_url) return post.jetpack_featured_media_url;
    if (post.featured_media_src_url) return post.featured_media_src_url;
    if (post.yoast_head_json?.og_image?.[0]?.url) return post.yoast_head_json.og_image[0].url;
    return '';
  } catch { return ''; }
};

const getCategories = (post) => {
  const categories = [];
  try {
    if (post._embedded?.['wp:term']) {
      post._embedded['wp:term'].flat().forEach(t => {
        if (t.taxonomy === 'category' && t.name) categories.push(decodeHTMLEntities(t.name));
      });
    }
  } catch {}
  return categories.length ? categories : ['Technology'];
};

for (const p of posts) {
  const titleRaw = p?.title?.rendered ?? p?.title ?? '';
  const url = p?.link ?? p?.guid?.rendered ?? p?.guid ?? '';
  if (!titleRaw || !url) continue;

  const excerptRaw = p?.excerpt?.rendered ?? '';
  const contentRaw = p?.content?.rendered ?? '';
  const publishedAt = toISO(p?.date_gmt ?? p?.date);
  const imageUrl = getImageUrl(p);
  const categories = getCategories(p);

  articles.push({
    title: clean(titleRaw),
    description: clean(excerptRaw || contentRaw || titleRaw).slice(0, 500),
    url,
    imageUrl,
    source: 'WordPress',
    publishedAt,
    categories,
    score: 0,
  });
}

const seen = new Set();
articles = articles.filter(a => {
  const key = a.url || 't:' + a.title;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

articles.sort((a, b) => new Date(b.publishedAt).getTime() - new Date(a.publishedAt).getTime());
articles = articles.slice(0, 12);

return [{ json: { articles, totalResults: articles.length, sources: ['WordPress'] } }];

// ─────────────────────────────────────────────
// FORMAT NEWSLETTER HTML
// Renders AI summaries into a branded HTML email
// ─────────────────────────────────────────────
// CUSTOMISE: Update SITE_NAME, SITE_URL, LOGO_URL,
//            BRAND_NAVY, BRAND_ORANGE, CTA_URL, and CTA_TEXT below.

const SITE_NAME    = 'YOUR COMPANY NAME';        // ← customise
const SITE_URL     = 'https://YOUR-SITE.com';    // ← customise
const LOGO_URL     = 'https://YOUR-SITE.com/wp-content/uploads/logo.png'; // ← customise
const BRAND_NAVY   = '#002657';
const BRAND_ORANGE = '#FA4616';
const CTA_URL      = 'https://YOUR-SITE.com/contact'; // ← customise
const CTA_TEXT     = 'Schedule a Consultation';        // ← customise

// ─── Parse AI output ───
const aiResponse = $json.output || $json.data || '';
let newsletterData;

function safeJSONStringParse(s) {
  if (!s) return null;
  try {
    const match = s.match(/\{[\s\S]*\}/);
    return match ? JSON.parse(match[0]) : null;
  } catch { return null; }
}

newsletterData = safeJSONStringParse(aiResponse);

if (!newsletterData || !Array.isArray(newsletterData.articles)) {
  newsletterData = {
    articles: [{
      headline: 'This Week on Our Blog',
      summary: (aiResponse || 'No AI summary available.').toString().slice(0, 600) + '…',
      url: '',
      imageUrl: '',
      category: 'Technology',
      date: '',
      word_count: 0,
    }],
    newsletter_date: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
    overview: 'Highlights from our latest blog posts.',
  };
}

// ─── Helpers ───
function formatDateHuman(input) {
  if (!input) return '';
  const d = new Date(input);
  if (isNaN(d.getTime())) return String(input);
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}

function renderArticleCard(a, index) {
  const hasImage = a.imageUrl && a.imageUrl.trim() !== '';
  const cat = a.category || 'Technology';
  const dateTxt = formatDateHuman(a.date || a.publishedAt || a.published_at || '');
  const metaParts = [cat, dateTxt].filter(Boolean).join(' • ');
  const imageUrl = hasImage ? a.imageUrl : LOGO_URL;
  const summary = (a.summary || '').toString().replace(/\n+/g, ' ').trim();

  return `
  <tr>
    <td style="padding: 0 0 24px 0;">
      <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#ffffff;border:1px solid #e5e7eb;border-radius:12px;overflow:hidden;">
        <tr>
          <td align="center" style="padding:0;">
            <a href="${a.url || '#'}" target="_blank" style="display:block;text-decoration:none;">
              <div style="width:100%;height:156px;overflow:hidden;">
                <img src="${imageUrl}" width="100%" alt="${(a.headline||'Article').replace(/"/g,'&quot;')}" style="display:block;width:100%;height:208px;object-fit:cover;object-position:center center;border:0;margin-top:-26px;">
              </div>
            </a>
          </td>
        </tr>
        <tr>
          <td style="padding:20px;">
            <div style="font-size:12px;font-weight:600;color:${BRAND_ORANGE};text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px;">${metaParts}</div>
            <a href="${a.url||'#'}" target="_blank" style="text-decoration:none;">
              <div style="font-size:20px;font-weight:700;color:#1e293b;line-height:1.3;margin-bottom:12px;">${a.headline||'Untitled Article'}</div>
            </a>
            <div style="font-size:15px;color:#4b5563;line-height:1.7;margin-bottom:16px;">${summary}</div>
            ${a.url ? `<a href="${a.url}" target="_blank" style="font-size:14px;font-weight:600;color:#1d4ed8;text-decoration:none;">Read full article &rarr;</a>` : ''}
          </td>
        </tr>
      </table>
    </td>
  </tr>`;
}

// ─── Build HTML ───
const newsletterHtml = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="x-apple-disable-message-reformatting">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${SITE_NAME} Weekly Digest — ${newsletterData.newsletter_date}</title>
  <style>
    img{border:0;outline:none;text-decoration:none;}
    table{border-collapse:collapse!important;}
    body,td{margin:0;padding:0;}
    @media only screen and (max-width:600px){.container{width:100%!important;}.mobile-pad{padding:12px!important;}}
  </style>
</head>
<body style="margin:0;padding:16px;background:#f1f5f9;font-family:Georgia,'Times New Roman',serif;line-height:1.6;color:#334155;">
  <center>
    <table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="max-width:680px;">
      <tr><td>
        <table class="container" role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="max-width:680px;background:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.08);">

          <!-- HEADER -->
          <tr>
            <td style="background:linear-gradient(135deg,${BRAND_NAVY} 0%,#003d7a 100%);padding:20px 24px 16px 24px;text-align:center;">
              <img src="${LOGO_URL}" width="140" alt="${SITE_NAME} Logo" style="display:block;max-width:140px;height:auto;margin:0 auto;">
              <div style="font-size:26px;font-weight:bold;color:#ffffff;margin:12px 0 4px 0;letter-spacing:-0.5px;">Weekly Digest</div>
              <div style="font-size:14px;font-style:italic;color:#94a3b8;margin-bottom:6px;">Your weekly roundup of the latest articles</div>
              <div style="font-size:13px;color:#cbd5e1;font-weight:500;">${newsletterData.newsletter_date}</div>
            </td>
          </tr>

          <!-- OVERVIEW -->
          <tr>
            <td style="padding:16px 20px 12px 20px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:linear-gradient(135deg,#f0f9ff 0%,#e0f2fe 100%);border-left:4px solid #0284c7;border-radius:0 8px 8px 0;">
                <tr><td style="padding:14px 20px;">
                  <div style="font-size:16px;font-weight:bold;color:#0369a1;margin-bottom:6px;">📋 This Week's Overview</div>
                  <div style="font-size:15px;color:#334155;line-height:1.6;">${newsletterData.overview||'Explore our latest articles.'}</div>
                </td></tr>
              </table>
            </td>
          </tr>

          <!-- ARTICLES -->
          <tr>
            <td style="padding:8px 20px 24px 20px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
                ${newsletterData.articles.map((a,i) => renderArticleCard(a,i)).join('')}
              </table>
            </td>
          </tr>

          <!-- CTA -->
          <tr>
            <td align="center" style="padding:0 20px 32px 20px;">
              <table role="presentation" cellpadding="0" cellspacing="0" border="0">
                <tr>
                  <td style="background:${BRAND_NAVY};border-radius:8px;">
                    <a href="${CTA_URL}" target="_blank" style="display:inline-block;padding:14px 32px;color:#ffffff;font-size:15px;font-weight:bold;text-decoration:none;border-radius:8px;background:${BRAND_NAVY};">${CTA_TEXT}</a>
                  </td>
                </tr>
              </table>
            </td>
          </tr>

          <!-- FOOTER -->
          <tr>
            <td style="background:#1e293b;padding:28px 24px;text-align:center;">
              <div style="font-size:18px;font-weight:bold;color:#ffffff;margin-bottom:6px;">${SITE_NAME}</div>
              <div style="font-size:13px;color:#94a3b8;margin-bottom:16px;">Keeping you informed every week</div>
              <div style="border-top:1px solid #334155;padding-top:16px;margin-top:8px;">
                <a href="${SITE_URL}" style="color:#60a5fa;text-decoration:none;font-size:13px;margin:0 12px;">Website</a>
                <span style="color:#475569;">•</span>
                <a href="${SITE_URL}/unsubscribe" style="color:#60a5fa;text-decoration:none;font-size:13px;margin:0 12px;">Unsubscribe</a>
              </div>
              <div style="font-size:11px;color:#64748b;margin-top:16px;">© ${new Date().getFullYear()} ${SITE_NAME}. All rights reserved.</div>
            </td>
          </tr>

        </table>
      </td></tr>
    </table>
  </center>
</body>
</html>`;

return {
  newsletter_html: newsletterHtml,
  newsletter_date: newsletterData.newsletter_date,
  article_count: Array.isArray(newsletterData.articles) ? newsletterData.articles.length : 0,
  overview: newsletterData.overview || '',
  articles: newsletterData.articles,
};
